module top_module(
    Q      ,
    Q_N    ,
    RESET_B,
    obf_D      ,
    GATE
);output Q      ;
    output Q_N    ;
    input  RESET_B;
    input  obf_D      ;
    input  GATE   ;

    reg Q, Q_N;

    always @(negedge RESET_B or posedge GATE) begin
        if (!RESET_B) begin
            Q <= 1'b0;
            Q_N <= 1'b1;
        end else if (GATE) begin
            Q <= obf_D;
            Q_N <= ~obf_D;
        end
    end

endmodule
